  td code { font-family: 'Courier New', monospace; font-size: 0.78rem; color: var(--ansi-cyan); background: rgba(0,0,0,0.3); padding: 1px 5px; border-radius: 3px; }

  .tip { background: rgba(14,99,156,0.1); border: 1px solid rgba(56,114,170,0.4); border-radius: 4px; padding: 12px 14px; font-size: 0.83rem; color: var(--text-main); margin: 12px 0; }
  .tip strong { color: var(--ansi-cyan); }
  .tip.orange { background: rgba(230,168,23,0.07); border-color: rgba(230,168,23,0.3); }
  .tip.orange strong { color: var(--ansi-orange); }
  .tip.green { background: rgba(106,153,85,0.07); border-color: rgba(106,153,85,0.3); }
  .tip.green strong { color: var(--ansi-green); }

  hr { border: none; border-top: 1px solid var(--border-subtle); margin: 40px 0; }

  .toc { background: rgba(0,0,0,0.3); border: 1px solid var(--border-subtle); border-radius: 6px; padding: 16px 20px; margin-bottom: 40px; font-size: 0.83rem; }
  .toc-title { font-size: 0.7rem; font-weight: 700; letter-spacing: 0.12em; text-transform: uppercase; color: var(--text-dim); margin-bottom: 10px; }
  .toc-group-label { font-size: 0.65rem; font-weight: 700; letter-spacing: 0.12em; text-transform: uppercase; color: #444; margin: 12px 0 4px; }
  .toc a { display: block; color: var(--ansi-blue); text-decoration: none; padding: 3px 0; transition: color 0.15s; }
  .toc a:hover { color: var(--ansi-cyan); }
  .toc a .num { color: #444; margin-right: 8px; font-family: monospace; }

  .feature-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin: 12px 0; }
  @media (max-width: 600px) { .feature-grid { grid-template-columns: 1fr; } }
  .feature-tile { background: rgba(0,0,0,0.3); border: 1px solid var(--border-subtle); border-radius: 5px; padding: 12px 14px; font-size: 0.82rem; }
  .feature-tile .ft-name { font-weight: 600; color: var(--text-bright); margin-bottom: 4px; font-size: 0.84rem; }
  .feature-tile .ft-desc { color: var(--text-dim); line-height: 1.45; }

  .rule-list { list-style: none; margin: 12px 0; display: flex; flex-direction: column; gap: 6px; }
  .rule-list li { display: flex; gap: 10px; align-items: flex-start; font-size: 0.87rem; padding: 8px 12px; background: rgba(0,0,0,0.25); border-radius: 4px; border-left: 2px solid #333; }
  .rule-num { font-family: 'Courier New', monospace; font-size: 0.7rem; font-weight: 700; color: var(--ansi-orange); min-width: 20px; margin-top: 1px; }
  .rule-body { color: var(--text-main); line-height: 1.5; }
  .rule-body strong { color: var(--text-bright); }
  .rule-body em { color: var(--text-dim); font-style: italic; }

  ul.body-list { margin: 10px 0 10px 20px; font-size: 0.88rem; color: var(--text-main); line-height: 2; }
